import React, { useEffect, useState } from 'react';
import { 
  Users, 
  Activity, 
  Dumbbell, 
  Flame, 
  ArrowUpRight, 
  Calendar,
  Clock,
  Loader2
} from 'lucide-react';
import { supabase } from './lib/supabase';

export function DashboardOverview() {
  const [stats, setStats] = useState({
    totalClients: 0,
    upcomingClasses: [] as any[],
    recentActivity: [] as any[],
  });
  const [loading, setLoading] = useState(true);

  // Cargar estadísticas reales desde Supabase
  useEffect(() => {
    async function fetchDashboardData() {
      try {
        // 1. Obtener Total de Clientes de la tabla 'profiles'
        const { count: clientCount } = await supabase
          .from('profiles')
          .select('*', { count: 'exact', head: true })
          .eq('role', 'client');

        // 2. Obtener Clases de Hoy de tu tabla real 'classes'
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const tomorrow = new Date(today);
        tomorrow.setDate(tomorrow.getDate() + 1);

        const { data: classesList } = await supabase
          .from('classes')
          .select('id, title, start_time, trainer')
          .gte('start_time', today.toISOString())
          .lt('start_time', tomorrow.toISOString())
          .order('start_time', { ascending: true });

        // 3. Obtener Actividad Reciente (Últimos 3 perfiles creados)
        const { data: recentProfiles } = await supabase
          .from('profiles')
          .select('id, first_name, last_name, created_at')
          .order('created_at', { ascending: false })
          .limit(3);

        setStats({
          totalClients: clientCount || 0,
          upcomingClasses: classesList || [],
          recentActivity: recentProfiles || [],
        });
      } catch (err) {
        console.error("Error cargando Dashboard:", err);
      } finally {
        setLoading(false);
      }
    }

    fetchDashboardData();
  }, []);

  if (loading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="w-10 h-10 text-[#39FF14] animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      {/* Cabecera */}
      <div>
        <h1 className="text-3xl font-bold text-white tracking-tight">Resumen General</h1>
        <p className="text-gray-400 mt-1">Datos en tiempo real de tu base de datos GymPro.</p>
      </div>

      {/* Tarjetas de Estadísticas (KPIs) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

        {/* Tarjeta 1: Datos Reales de Supabase (Clientes) */}
        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl relative overflow-hidden group hover:border-[#39FF14]/50 transition-colors">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
            <Users size={64} className="text-[#39FF14]" />
          </div>
          <div className="flex justify-between items-start relative z-10">
            <div>
              <p className="text-sm font-medium text-gray-400">Total Clientes</p>
              <h3 className="text-4xl font-black text-white mt-2">
                {stats.totalClients}
              </h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-[#39FF14]/10 flex items-center justify-center text-[#39FF14]">
              <Users size={20} />
            </div>
          </div>
        </div>

        {/* Tarjetas 2, 3 y 4: Datos Visuales (Mocks para mantener el diseño) */}
        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-[#2a2a2a] transition-colors">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Asistencia Hoy</p>
              <h3 className="text-4xl font-black text-white mt-2">84</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-blue-500/10 flex items-center justify-center text-blue-500">
              <Activity size={20} />
            </div>
          </div>
          <div className="mt-4 flex items-center gap-2 text-sm text-gray-400">
            <span>Pico estimado a las 18:00</span>
          </div>
        </div>

        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-[#2a2a2a] transition-colors">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Clases Activas</p>
              <h3 className="text-4xl font-black text-white mt-2">{stats.upcomingClasses.length}</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-purple-500/10 flex items-center justify-center text-purple-500">
              <Dumbbell size={20} />
            </div>
          </div>
          <div className="mt-4 flex items-center gap-2 text-sm text-gray-400">
            <span>Para el día de hoy</span>
          </div>
        </div>

        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-[#2a2a2a] transition-colors">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Calorías Quemadas</p>
              <h3 className="text-4xl font-black text-white mt-2">42K</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-orange-500/10 flex items-center justify-center text-orange-500">
              <Flame size={20} />
            </div>
          </div>
          <div className="mt-4 flex items-center gap-2 text-sm text-gray-400">
            <span>Estimación global del día</span>
          </div>
        </div>
      </div>

      {/* Sección Inferior: Dos columnas */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Próximas Sesiones (Datos reales de 'classes') */}
        <div className="lg:col-span-2 bg-[#121212] border border-[#2a2a2a] rounded-2xl p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-white flex items-center gap-2">
              <Calendar className="text-[#39FF14]" size={20} />
              Próximas Sesiones Hoy
            </h2>
          </div>

          <div className="space-y-4">
            {stats.upcomingClasses.length > 0 ? (
              stats.upcomingClasses.map((cls) => {
                const timeStr = new Date(cls.start_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
                const [hours, minutes] = timeStr.split(':');

                return (
                  <div key={cls.id} className="flex items-center justify-between p-4 rounded-xl bg-[#1a1a1a] border border-[#2a2a2a] hover:border-[#39FF14]/30 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-lg bg-[#39FF14]/10 text-[#39FF14] flex flex-col items-center justify-center font-bold">
                        <span className="text-sm leading-none">{hours}</span>
                        <span className="text-xs leading-none">{minutes}</span>
                      </div>
                      <div>
                        <h4 className="font-bold text-white">{cls.title}</h4>
                      </div>
                    </div>
                    <div className="text-right hidden sm:block">
                      <span className="text-sm font-medium text-gray-400 bg-[#121212] px-3 py-1 rounded-full border border-[#2a2a2a]">
                        Coach: {cls.trainer || 'Sin asignar'}
                      </span>
                    </div>
                  </div>
                );
              })
            ) : (
              <p className="text-gray-500 text-sm italic py-4">No hay clases programadas para el día de hoy.</p>
            )}
          </div>
        </div>

        {/* Actividad Reciente (Datos reales de 'profiles') */}
        <div className="bg-[#121212] border border-[#2a2a2a] rounded-2xl p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-white flex items-center gap-2">
              <Clock className="text-[#39FF14]" size={20} />
              Últimos Registros
            </h2>
          </div>

          <div className="space-y-6 relative before:absolute before:inset-0 before:ml-5 before:-translate-x-px md:before:mx-auto md:before:translate-x-0 before:h-full before:w-0.5 before:bg-gradient-to-b before:from-[#39FF14]/20 before:via-[#2a2a2a] before:to-transparent">
            {stats.recentActivity.map((user) => (
              <div key={user.id} className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group is-active">
                {/* Punto de la línea de tiempo */}
                <div className="flex items-center justify-center w-10 h-10 rounded-full border-4 border-[#121212] bg-[#1a1a1a] group-hover:bg-[#39FF14]/20 text-[#39FF14] shadow shrink-0 md:order-1 md:group-odd:-translate-x-1/2 md:group-even:translate-x-1/2 z-10 transition-colors">
                  <div className="w-2 h-2 bg-[#39FF14] rounded-full" />
                </div>

                {/* Tarjeta de actividad */}
                <div className="w-[calc(100%-4rem)] md:w-[calc(50%-2.5rem)] p-4 rounded-xl bg-[#1a1a1a] border border-[#2a2a2a] shadow">
                  <div className="flex items-center justify-between mb-1">
                    <time className="text-xs font-medium text-[#39FF14]">
                      {new Date(user.created_at).toLocaleDateString()}
                    </time>
                  </div>
                  <div className="text-sm text-gray-300">
                    Nuevo cliente registrado: <span className="font-bold text-white">{user.first_name} {user.last_name}</span>
                  </div>
                </div>
              </div>
            ))}

            {stats.recentActivity.length === 0 && (
              <p className="text-gray-500 text-sm italic">No hay actividad reciente.</p>
            )}
          </div>
        </div>

      </div>
    </div>
  );
}
